import React, { useState } from 'react';
import { Outlet, NavLink } from 'react-router-dom';

const navLinks = [
  { to: '/',            icon: '⊞',  label: 'Overview' },
  { to: '/trucks',      icon: '◈',  label: 'Truck Management' },
  { to: '/scrap',       icon: '↺',  label: 'Scrap Management' },
  { to: '/diesel',      icon: '◉',  label: 'Diesel Inventory' },
  { to: '/dashboard',   icon: '▦',  label: 'Dashboard' },
  { to: '/drivers',     icon: '◷',  label: 'Driver Advances' },
  { to: '/maintenance', icon: '⚙',  label: 'Maintenance Log' },
  { to: '/customers',   icon: '◫',  label: 'Customer Ledger' },
];

export default function Layout() {
  const [collapsed, setCollapsed] = useState(false);

  return (
    <div style={s.shell}>
      {/* Sidebar */}
      <aside style={{ ...s.sidebar, width: collapsed ? 64 : 230 }}>
        {/* Logo */}
        <div style={s.logoBlock}>
          <div style={s.logoMark}>M</div>
          {!collapsed && (
            <div style={s.logoText}>
              <div style={s.logoName}>Maruti Group</div>
              <div style={s.logoSub}>Transport Division</div>
            </div>
          )}
        </div>

        <div style={s.divider} />

        {/* Nav */}
        <nav style={s.nav}>
          {navLinks.map(l => (
            <NavLink
              key={l.to}
              to={l.to}
              end={l.to === '/'}
              style={({ isActive }) => ({
                ...s.link,
                ...(isActive ? s.linkActive : {}),
                justifyContent: collapsed ? 'center' : 'flex-start',
              })}
            >
              <span style={s.linkIcon}>{l.icon}</span>
              {!collapsed && <span style={s.linkLabel}>{l.label}</span>}
            </NavLink>
          ))}
        </nav>

        {/* Collapse toggle */}
        <button style={s.collapseBtn} onClick={() => setCollapsed(c => !c)}>
          {collapsed ? '→' : '← Collapse'}
        </button>
      </aside>

      {/* Main */}
      <div style={s.body}>
        <header style={s.topbar}>
          <div style={s.topbarTitle}>Maruti Group · Transport Management System</div>
          <div style={s.topbarDate}>{new Date().toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</div>
        </header>
        <main style={s.main}>
          <Outlet />
        </main>
      </div>
    </div>
  );
}

const NAVY   = '#0f2542';
const ACTIVE = '#e8f0fe';
const ACCENT = '#1a56db';

const s = {
  shell:       { display: 'flex', minHeight: '100vh', background: '#f1f5f9', fontFamily: "'Inter', 'Segoe UI', sans-serif" },

  sidebar:     { background: '#fff', borderRight: '1px solid #e2e8f0', display: 'flex', flexDirection: 'column', flexShrink: 0, transition: 'width 0.2s ease', overflow: 'hidden', position: 'sticky', top: 0, height: '100vh' },

  logoBlock:   { display: 'flex', alignItems: 'center', gap: 12, padding: '20px 16px 16px' },
  logoMark:    { width: 36, height: 36, borderRadius: 8, background: '#166534', color: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 800, fontSize: 18, flexShrink: 0 },
  logoName:    { fontSize: 14, fontWeight: 700, color: NAVY, whiteSpace: 'nowrap' },
  logoSub:     { fontSize: 11, color: '#94a3b8', marginTop: 1, whiteSpace: 'nowrap' },
  logoText:    {},

  divider:     { height: 1, background: '#e2e8f0', margin: '0 16px 12px' },

  nav:         { display: 'flex', flexDirection: 'column', gap: 2, padding: '0 8px', flex: 1 },
  link:        { display: 'flex', alignItems: 'center', gap: 10, padding: '9px 10px', borderRadius: 8, color: '#475569', textDecoration: 'none', fontSize: 13, fontWeight: 500, transition: 'background 0.15s' },
  linkActive:  { background: ACTIVE, color: ACCENT, fontWeight: 700 },
  linkIcon:    { fontSize: 16, width: 20, textAlign: 'center', flexShrink: 0 },
  linkLabel:   { whiteSpace: 'nowrap' },

  collapseBtn: { margin: '12px 8px 20px', padding: '8px', background: 'none', border: '1px solid #e2e8f0', borderRadius: 8, cursor: 'pointer', fontSize: 11, color: '#94a3b8', textAlign: 'center' },

  body:        { flex: 1, display: 'flex', flexDirection: 'column', minWidth: 0 },
  topbar:      { background: '#fff', borderBottom: '1px solid #e2e8f0', padding: '0 32px', height: 52, display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexShrink: 0 },
  topbarTitle: { fontSize: 13, fontWeight: 600, color: NAVY },
  topbarDate:  { fontSize: 12, color: '#94a3b8' },

  main:        { padding: '32px', flex: 1 },
};
